DROP TABLE IF EXISTS `re_property_availability_rules`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `re_property_availability_rules` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `property_id` bigint unsigned NOT NULL,
  `name` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Rule name (e.g., "Summer Season", "Holiday Pricing")',
  `type` enum('seasonal_pricing','blocked_period','minimum_stay','special_rate') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'seasonal_pricing',
  `start_date` date NOT NULL,
  `end_date` date NOT NULL,
  `days_of_week` json DEFAULT NULL COMMENT 'Array of days [0=Sunday, 1=Monday, etc.] or null for all days',
  `price_modifier` decimal(8,2) DEFAULT NULL COMMENT 'Multiplier for base price (1.5 = 150% of base price)',
  `fixed_price` decimal(15,2) DEFAULT NULL COMMENT 'Fixed price override',
  `minimum_stay_override` int DEFAULT NULL COMMENT 'Override minimum stay for this period',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `priority` int NOT NULL DEFAULT '0' COMMENT 'Higher priority rules override lower priority ones',
  `description` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_property_active` (`property_id`,`is_active`),
  KEY `idx_property_date_range` (`property_id`,`start_date`,`end_date`),
  KEY `idx_type_active` (`type`,`is_active`),
  KEY `idx_rule_lookup` (`property_id`,`type`,`is_active`,`priority`),
  CONSTRAINT `re_property_availability_rules_property_id_foreign` FOREIGN KEY (`property_id`) REFERENCES `re_properties` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
