DROP TABLE IF EXISTS `re_vacation_rental_bookings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `re_vacation_rental_bookings` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `booking_number` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Unique booking reference number',
  `property_id` bigint unsigned NOT NULL,
  `account_id` bigint unsigned DEFAULT NULL COMMENT 'Registered user account',
  `guest_name` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `guest_email` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `guest_phone` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `guest_address` text COLLATE utf8mb4_unicode_ci,
  `check_in_date` date NOT NULL,
  `check_out_date` date NOT NULL,
  `nights_count` int NOT NULL,
  `guests_count` int NOT NULL,
  `base_price_per_night` decimal(15,2) NOT NULL,
  `total_nights_cost` decimal(15,2) NOT NULL,
  `cleaning_fee` decimal(15,2) NOT NULL DEFAULT '0.00',
  `security_deposit` decimal(15,2) NOT NULL DEFAULT '0.00',
  `service_fee` decimal(15,2) NOT NULL DEFAULT '0.00',
  `taxes` decimal(15,2) NOT NULL DEFAULT '0.00',
  `total_amount` decimal(15,2) NOT NULL,
  `status` enum('pending','confirmed','cancelled','completed','no_show') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `payment_status` enum('pending','partial','paid','refunded') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `special_requests` text COLLATE utf8mb4_unicode_ci,
  `cancellation_reason` text COLLATE utf8mb4_unicode_ci,
  `cancelled_at` timestamp NULL DEFAULT NULL,
  `internal_notes` text COLLATE utf8mb4_unicode_ci,
  `confirmation_sent_at` timestamp NULL DEFAULT NULL,
  `reminder_sent_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `re_vacation_rental_bookings_booking_number_unique` (`booking_number`),
  KEY `re_vacation_rental_bookings_account_id_foreign` (`account_id`),
  KEY `idx_property_status` (`property_id`,`status`),
  KEY `idx_property_dates` (`property_id`,`check_in_date`,`check_out_date`),
  KEY `idx_booking_dates` (`check_in_date`,`check_out_date`),
  KEY `idx_status_checkin` (`status`,`check_in_date`),
  KEY `idx_guest_email` (`guest_email`),
  KEY `idx_booking_number` (`booking_number`),
  CONSTRAINT `re_vacation_rental_bookings_account_id_foreign` FOREIGN KEY (`account_id`) REFERENCES `re_accounts` (`id`) ON DELETE SET NULL,
  CONSTRAINT `re_vacation_rental_bookings_property_id_foreign` FOREIGN KEY (`property_id`) REFERENCES `re_properties` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=17 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
